// =============================================================
// DEMO: window.__acAsync — Async Data Receiver
// =============================================================

var receivedItems = [];
var totalExpected = 5; // số lượng iteration của AsyncTask

// Cách 1: Nhận 1 key cụ thể ('item')
window.__acAsync.onReceive('item', function(value) {
    console.log('Received item:', value);

    // Lưu vào list
    receivedItems.push(value);

    // Update UI
    updateDashboard(value);
});

// Cách 2 (optional): Nhận TẤT CẢ data — hàm này gọi mỗi lần bất kỳ key nào được push
// window.__acAsync.onReceive(function(allData) {
//     console.log('All async data:', JSON.stringify(allData));
// });

function updateDashboard(latestValue) {
    // Status
    var icon = document.getElementById('statusIcon');
    var text = document.getElementById('statusText');
    var count = document.getElementById('itemCount');
    var progress = document.getElementById('progressBar');
    var list = document.getElementById('itemList');
    var raw = document.getElementById('rawData');

    var n = receivedItems.length;
    var pct = Math.min(100, Math.round((n / totalExpected) * 100));

    icon.textContent = pct >= 100 ? '✅' : '⚡';
    text.textContent = pct >= 100 ? 'Hoàn thành!' : 'Đang nhận dữ liệu...';
    count.textContent = n + ' items';
    progress.style.width = pct + '%';
    progress.textContent = pct + '%';

    if (pct >= 100) {
        progress.classList.add('done');
    }

    // Raw data
    raw.textContent = latestValue;

    // Render list
    var html = '';
    for (var i = receivedItems.length - 1; i >= 0; i--) {
        var item = receivedItems[i];
        var ts = new Date().toLocaleTimeString();
        html += '<div class="item-row">' +
            '<span class="item-idx">#' + (i + 1) + '</span>' +
            '<span class="item-val">' + escapeHtml(item) + '</span>' +
            '<span class="item-time">' + ts + '</span>' +
            '</div>';
    }
    list.innerHTML = html;
}

function escapeHtml(str) {
    var d = document.createElement('div');
    d.textContent = str;
    return d.innerHTML;
}

// Cách 3: Đọc trực tiếp (polling) — không cần callback
