body {
    font-family: 'Segoe UI', system-ui, sans-serif;
    margin: 0; padding: 0;
    background: #0f172a;
    color: #e2e8f0;
}
.container { padding: 20px; }
h1 { margin: 0 0 4px; font-size: 20px; color: #38bdf8; }
.desc { font-size: 12px; color: #94a3b8; margin: 0 0 16px; }
kbd {
    background: #1e293b; border: 1px solid #334155;
    border-radius: 4px; padding: 1px 6px; font-size: 11px;
    color: #38bdf8;
}

/* Status */
.status-bar {
    display: flex; align-items: center; gap: 8px;
    background: #1e293b; border-radius: 8px;
    padding: 10px 14px; margin-bottom: 12px;
    font-size: 14px;
}
#statusIcon { font-size: 18px; }
.badge {
    margin-left: auto;
    background: #0ea5e9; color: #fff;
    border-radius: 12px; padding: 2px 10px;
    font-size: 12px; font-weight: 600;
}

/* Progress */
.progress-wrap {
    background: #1e293b; border-radius: 6px;
    height: 22px; margin-bottom: 16px; overflow: hidden;
}
.progress-bar {
    height: 100%; background: linear-gradient(90deg, #0ea5e9, #6366f1);
    border-radius: 6px; transition: width 0.4s ease;
    display: flex; align-items: center; justify-content: center;
    font-size: 11px; font-weight: 600; color: #fff;
    min-width: 0;
}
.progress-bar.done {
    background: linear-gradient(90deg, #10b981, #34d399);
}

/* Item list */
.item-list {
    background: #1e293b; border-radius: 8px;
    padding: 8px; max-height: 200px;
    overflow-y: auto; margin-bottom: 16px;
}
.empty-state {
    text-align: center; color: #64748b;
    padding: 20px; font-size: 13px;
}
.item-row {
    display: flex; align-items: center; gap: 10px;
    padding: 6px 10px; border-radius: 6px;
    margin-bottom: 4px;
    background: #0f172a;
    animation: fadeIn 0.3s ease;
}
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}
.item-idx {
    color: #0ea5e9; font-weight: 700;
    font-size: 12px; min-width: 30px;
}
.item-val {
    flex: 1; font-size: 13px;
    color: #e2e8f0;
    overflow: hidden; text-overflow: ellipsis;
    white-space: nowrap;
}
.item-time {
    color: #64748b; font-size: 11px;
    white-space: nowrap;
}

/* Raw */
.raw-section {
    background: #1e293b; border-radius: 8px;
    padding: 12px;
}
.raw-section h3 {
    margin: 0 0 6px; font-size: 13px;
    color: #94a3b8; font-weight: 600;
}
pre {
    margin: 0; font-size: 12px;
    color: #fbbf24; font-family: 'Cascadia Code', Consolas, monospace;
    white-space: pre-wrap; word-break: break-all;
}
